function e(n){const t=Number(n)||0;return new Intl.NumberFormat("id-ID",{style:"currency",currency:"IDR",minimumFractionDigits:0,maximumFractionDigits:0}).format(t)}function i(n,t={}){if(!n)return"—";const r=typeof n=="string"?new Date(n):n;return Number.isNaN(r.getTime())?"—":new Intl.DateTimeFormat("id-ID",{day:"numeric",month:"long",year:"numeric",...t}).format(r)}function m(n){if(!n)return"—";const t=new Date(n);return new Intl.DateTimeFormat("id-ID",{day:"numeric",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"}).format(t)}export{m as a,i as b,e as f};
